    97→static int
    98→run_cmd(const char *cmd)
    99→{
   100→    int ret = 0;
   101→    char cmdstring[256];
   102→
   103→    sprintf(cmdstring, "%s\n", cmd);
   104→    size_t len = strlen(cmdstring);
   105→
   106→    if (shell_stdin != NULL) {
   107→        ret = fwrite(cmdstring, 1, len, shell_stdin);
   108→        fflush(shell_stdin);
   109→    }
   110→
   111→    return ret == len;
   112→}
